/**
 * @param {number} n
 * @param {number[][]} edges
 * @return {number}
 */
function solve(n, edges) {
    // This problem can be modeled using Disjoint Set Union (DSU) with path compression and union by rank/size,
    // augmented to maintain the parity of path weights.
    //
    // For any two nodes u and v in the same connected component, we want to maintain the parity
    // of the path weight between them. Let's define dist[i] as the parity of the path weight
    // from node i to the representative (root) of its set.
    // dist[i] = 0 means the path from i to root has even weight.
    // dist[i] = 1 means the path from i to root has odd weight.

    const parent = Array(n).fill(0).map((_, i) => i);
    // parity[i] stores the parity of the path weight from i to parent[i].
    const parity = Array(n).fill(0);

    /**
     * Finds the root of the set containing i, applying path compression and updating parity.
     * @param {number} i
     * @returns {number} The root of the set.
     */
    function find(i) {
        if (parent[i] === i) {
            return i;
        }
        // Recursively find the root and update the parent's parity along the way
        const root = find(parent[i]);

        // New parity[i] = (old parity[i] + parity[parent[i]]) % 2
        // where parity[parent[i]] is the parity from old parent[i] to the final root.
        parity[i] = (parity[i] + parity[parent[i]]) % 2;

        parent[i] = root;
        return root;
    }

    let addedEdgesCount = 0;

    for (const [u, v, w] of edges) {
        const rootU = find(u);
        const rootV = find(v);

        // The condition "every cycle's edge weight sum is even" is equivalent to 
        // saying that in the spanning forest formed by the selected edges, 
        // for any two nodes u and v connected by an edge (u, v) with weight w,
        // if they are already in the same component, the path weight between them 
        // must have parity w.

        if (rootU !== rootV) {
            // Case 1: u and v are in different components.
            // Adding the edge (u, v) creates no cycle, so the condition is trivially satisfied.
            // We merge the sets. We choose rootU as the new parent of rootV.

            parent[rootV] = rootU;

            // We need to set parity[rootV] such that the path from rootV to rootU has the correct parity.
            // Path: rootV -> v --(w)--> u -> rootU
            // We know:
            // 1. Parity(u -> rootU) = parity[u]
            // 2. Parity(v -> rootV) = parity[v]
            // 3. Parity(u -> v) = w
            //
            // We want Parity(rootV -> rootU) = P.
            // P = Parity(rootV -> v) + Parity(v -> u) + Parity(u -> rootU)
            // Parity(rootV -> v) = Parity(v -> rootV) = parity[v] (since path is reversible)
            // Parity(v -> u) = w
            // Parity(u -> rootU) = parity[u]
            // P = parity[v] + w + parity[u] (mod 2)

            parity[rootV] = (parity[v] + w + parity[u]) % 2;
            addedEdgesCount++;
        } else {
            // Case 2: u and v are already in the same component (rootU == rootV).
            // Adding (u, v) creates a cycle. The cycle consists of the edge (u, v) and the 
            // path already existing between u and v in the spanning forest.

            // The path parity between u and v in the existing forest is:
            // Parity(u -> rootU) + Parity(rootU -> v) (where rootU->v is path v->rootU reversed)
            // PathParity(u, v) = (parity[u] + parity[v]) % 2

            // The new cycle weight parity is:
            // CycleParity = PathParity(u, v) + w
            // CycleParity = (parity[u] + parity[v] + w) % 2

            // The edge is added ONLY if CycleParity is 0 (even).
            if ((parity[u] + parity[v] + w) % 2 === 0) {
                addedEdgesCount++;
                // If we add it, the structure remains consistent, no DSU update needed beyond path compression already done.
            }
            // If CycleParity is 1 (odd), the edge is rejected.
        }
    }

    return addedEdgesCount;
}

