    // Returns the root of the set containing i.
    def find(i: Int): Int = {
      if (parent(i) == i) {
        i
      } else {
        // Recursively find the root
        val root = find(parent(i))

        // Update parity[i]: New parity = (old parity[i] + parity[parent[i]]) % 2
        // parity[parent[i]] now stores the parity from old parent[i] to the final root.
        parity(i) = (parity(i) + parity(parent(i))) % 2

        // Path compression
        parent(i) = root
        root
      }
    }

    var addedEdgesCount: Long = 0

    for (edge <- edges) {
      val u = edge(0).toInt
      val v = edge(1).toInt
      val w = edge(2).toInt

      val rootU = find(u)
      val rootV = find(v)

      if (rootU != rootV) {
        // Case 1: u and v are in different components. Add the edge.

        // Merge sets: Make rootU the parent of rootV.
        parent(rootV) = rootU

        // Set parity[rootV] such that the path from rootV to rootU has the correct parity.
        // Path: rootV -> v --(w)--> u -> rootU
        // We want Parity(rootV -> rootU) = P.
        // P = Parity(rootV -> v) + Parity(v -> u) + Parity(u -> rootU) (mod 2)
        // Parity(rootV -> v) = Parity(v -> rootV) = parity[v]
        // Parity(v -> u) = w
        // Parity(u -> rootU) = parity[u]
        // P = parity[v] + w + parity[u] (mod 2)

        parity(rootV) = (parity(v) + w + parity(u)) % 2

        addedEdgesCount += 1
      } else {
        // Case 2: u and v are already in the same component. Check cycle condition.

        // PathParity(u, v) = (parity[u] + parity[v]) % 2
        // CycleParity = PathParity(u, v) + w
        // CycleParity = (parity[u] + parity[v] + w) % 2

