    // 0 for even, 1 for odd.
    val parity = IntArray(N) { 0 }

    // Find operation with path compression and parity update
    def find(i: Int): (Int, Int) = {
      if (parent(i) == i) {
        (i, 0) // Root, distance to self is 0
      } else {
        // Recurse to find root and the parity from parent[i] to root
        val (root, parityFromParentToRoot) = find(parent(i))

        // Update parity[i]: new parity from i to root = (old parity from i to parent) + (parity from parent to root) mod 2
        parity(i) = (parity(i) + parityFromParentToRoot) % 2

        // Path compression
        parent(i) = root

        (root, parity(i))
      }
    }

    var addedEdgesCount = 0L

    for (edge in edges) {
      val u = edge(0).toInt
      val v = edge(1).toInt
      val w = edge(2).toInt

      // Find roots and parities to roots for u and v
      val (rootU, parityU) = find(u)
      val (rootV, parityV) = find(v)

      if (rootU != rootV) {
        // Case 1: u and v are in different components. Merge sets.
        // We merge rootV's set into rootU's set (arbitrarily).
        parent(rootV) = rootU

        // We need to set parity[rootV] such that:
        // Parity(rootV -> rootU) = Parity(rootV -> v) + Parity(v -> u) + Parity(u -> rootU) mod 2
        // Parity(rootV -> v) = parityV
        // Parity(v -> u) = w
        // Parity(u -> rootU) = parityU
        // P = parityV + w + parityU (mod 2)
        parity(rootV) = (parityV + w + parityU) % 2

        addedEdgesCount += 1
      } else {
        // Case 2: u and v are already in the same component. Check cycle parity.

        // Path parity between u and v in the existing forest:
        // Parity(u -> v) = Parity(u -> rootU) + Parity(rootU -> v) mod 2
        // Since Parity(rootU -> v) is the inverse of Parity(v -> rootU), and we are in GF(2), they are the same.
